"""Resolve provisioner scaffold source directory (bundled tree vs env override)."""

from __future__ import annotations

import os
from pathlib import Path

_BUNDLED_SCAFFOLD_ROOT = (
    Path(__file__).resolve().parent / "fixtures" / "rebase-ai-scaffold"
)


def bundled_scaffold_source_root() -> Path:
    """In-repo rebase-ai-scaffold tree shipped with the provisioner product."""
    return _BUNDLED_SCAFFOLD_ROOT


def resolve_scaffold_source_root() -> Path:
    """Return ``PROVISION_SCAFFOLD_SOURCE_ROOT`` when set, else the bundled fixture tree."""
    raw = os.environ.get("PROVISION_SCAFFOLD_SOURCE_ROOT", "").strip()
    if raw:
        path = Path(raw)
        if not path.is_absolute():
            raise ValueError(f"PROVISION_SCAFFOLD_SOURCE_ROOT must be an absolute path, got: {raw!r}")
        return path
    return bundled_scaffold_source_root()

