def _parse_ngrok_reserved_domains(raw: str) -> tuple[str, ...]:
    domains = tuple(part.strip() for part in raw.split(",") if part.strip())
    if not domains:
        raise ValueError(
            "NGROK_RESERVED_DOMAINS must list at least one reserved ngrok hostname "
            "(comma-separated, e.g. rebase001.ngrok.app)"
        )
    invalid = [host for host in domains if not _NGROK_RESERVED_HOSTNAME_RE.fullmatch(host)]
    if invalid:
        raise ValueError(
            "NGROK_RESERVED_DOMAINS contains invalid hostname(s): "
            + ", ".join(invalid)
        )
    return domains


